#include <stdio.h>
int max(int a, int b, int c) { return (a > b) ? (a > c ? a : c) : (b > c ? b : c); }
int maxTrainingMerits(int n, int matrix[][3]) {
    int dp[n][3];
    dp[0][0] = matrix[0][0];
    dp[0][1] = matrix[0][1];
    dp[0][2] = matrix[0][2];
    for (int i = 1; i < n; i++) {
        dp[i][0] = max(dp[i-1][1], dp[i-1][2]) + matrix[i][0];
        dp[i][1] = max(dp[i-1][0], dp[i-1][2]) + matrix[i][1];
        dp[i][2] = max(dp[i-1][0], dp[i-1][1]) + matrix[i][2];
    }
    return max(dp[n-1][0], dp[n-1][1], dp[n-1][2]);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int matrix[n][3];
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d", &matrix[i][0], &matrix[i][1], &matrix[i][2]);
        }
        printf("%d\n", maxTrainingMerits(n, matrix));
    }
    return 0;
}

