import java.util.Scanner;
public class Main {
    public static int max(int a, int b, int c) { return (a > b) ? (a > c ? a : c) : (b > c ? b : c); }
    public static int maxTrainingMerits(int n, int[][] matrix) {
        int[][] dp = new int[n][3];
        dp[0][0] = matrix[0][0];
        dp[0][1] = matrix[0][1];
        dp[0][2] = matrix[0][2];
        for (int i = 1; i < n; i++) {
            dp[i][0] = max(dp[i-1][1], dp[i-1][2]) + matrix[i][0];
            dp[i][1] = max(dp[i-1][0], dp[i-1][2]) + matrix[i][1];
            dp[i][2] = max(dp[i-1][0], dp[i-1][1]) + matrix[i][2];
        }
        return max(dp[n-1][0], dp[n-1][1], dp[n-1][2]);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[][] matrix = new int[n][3];
            for (int i = 0; i < n; i++) {
                matrix[i][0] = sc.nextInt();
                matrix[i][1] = sc.nextInt();
                matrix[i][2] = sc.nextInt();
            }
            System.out.println(maxTrainingMerits(n, matrix));
        }
    }
}

